import React, { useState, useEffect, useRef } from 'react';
import { SendIcon, SettingsIcon, PlusIcon, TrashIcon, SaveIcon } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

const AIChat = () => {
  const [conversations, setConversations] = useState([]);
  const [activeConversationId, setActiveConversationId] = useState(null);
  const [message, setMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [apiKey, setApiKey] = useState('');
  const [tempApiKey, setTempApiKey] = useState('');
  const [apiEndpoint, setApiEndpoint] = useState('https://api.openai.com/v1/chat/completions');
  const [model, setModel] = useState('gpt-3.5-turbo');
  const messagesEndRef = useRef(null);

  // 从localStorage加载数据
  useEffect(() => {
    const savedConversations = localStorage.getItem('personal-workspace-conversations');
    const savedApiKey = localStorage.getItem('personal-workspace-api-key');
    const savedApiEndpoint = localStorage.getItem('personal-workspace-api-endpoint');
    const savedModel = localStorage.getItem('personal-workspace-model');
    
    if (savedConversations) {
      const parsedConversations = JSON.parse(savedConversations);
      setConversations(parsedConversations);
      if (parsedConversations.length > 0) {
        setActiveConversationId(parsedConversations[0].id);
      }
    }
    
    if (savedApiKey) {
      setApiKey(savedApiKey);
      setTempApiKey(savedApiKey);
    }
    
    if (savedApiEndpoint) {
      setApiEndpoint(savedApiEndpoint);
    }
    
    if (savedModel) {
      setModel(savedModel);
    }
  }, []);

  // 自动滚动到底部
  useEffect(() => {
    scrollToBottom();
  }, [conversations, activeConversationId]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // 保存对话到localStorage
  const saveConversations = (updatedConversations) => {
    localStorage.setItem('personal-workspace-conversations', JSON.stringify(updatedConversations));
    setConversations(updatedConversations);
  };

  // 保存API配置
  const saveApiKey = () => {
    localStorage.setItem('personal-workspace-api-key', tempApiKey);
    localStorage.setItem('personal-workspace-api-endpoint', apiEndpoint);
    localStorage.setItem('personal-workspace-model', model);
    setApiKey(tempApiKey);
    setShowSettings(false);
  };

  // 创建新对话
  const createNewConversation = () => {
    const newConversation = {
      id: uuidv4(),
      title: '新对话',
      messages: [],
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    
    const updatedConversations = [newConversation, ...conversations];
    saveConversations(updatedConversations);
    setActiveConversationId(newConversation.id);
  };

  // 删除对话
  const deleteConversation = (conversationId) => {
    if (window.confirm('确定要删除这个对话吗？')) {
      const updatedConversations = conversations.filter(conv => conv.id !== conversationId);
      saveConversations(updatedConversations);
      
      if (activeConversationId === conversationId) {
        setActiveConversationId(updatedConversations.length > 0 ? updatedConversations[0].id : null);
      }
    }
  };

  // 清空当前对话
  const clearCurrentConversation = () => {
    if (window.confirm('确定要清空当前对话吗？')) {
      const updatedConversations = conversations.map(conv =>
        conv.id === activeConversationId
          ? { ...conv, messages: [], updatedAt: new Date().toISOString() }
          : conv
      );
      saveConversations(updatedConversations);
    }
  };

  // 调用真实的AI API
  const callAIAPI = async (messages) => {
    try {
      const response = await fetch(apiEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify({
          model: model,
          messages: messages.map(msg => ({
            role: msg.role,
            content: msg.content
          })),
          max_tokens: 1000,
          temperature: 0.7
        })
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(`API调用失败: ${response.status} - ${errorData.error?.message || '未知错误'}`);
      }

      const data = await response.json();
      return data.choices[0].message.content;
    } catch (error) {
      console.error('AI API调用错误:', error);
      throw error;
    }
  };

  // 发送消息
  const sendMessage = async () => {
    if (!message.trim() || isLoading) return;
    
    if (!apiKey) {
      alert('请先配置API Key');
      setShowSettings(true);
      return;
    }

    const userMessage = {
      id: uuidv4(),
      role: 'user',
      content: message.trim(),
      timestamp: new Date().toISOString()
    };

    // 添加用户消息
    const currentConversation = conversations.find(conv => conv.id === activeConversationId);
    const updatedMessages = [...(currentConversation?.messages || []), userMessage];
    
    const updatedConversations = conversations.map(conv =>
      conv.id === activeConversationId
        ? {
            ...conv,
            messages: updatedMessages,
            title: conv.messages.length === 0 ? message.trim().substring(0, 30) : conv.title,
            updatedAt: new Date().toISOString()
          }
        : conv
    );
    saveConversations(updatedConversations);
    
    setMessage('');
    setIsLoading(true);

    try {
      // 调用真实的AI API
      const aiResponse = await callAIAPI(updatedMessages);
      
      const aiMessage = {
        id: uuidv4(),
        role: 'assistant',
        content: aiResponse,
        timestamp: new Date().toISOString()
      };

      // 添加AI响应
      const finalConversations = conversations.map(conv =>
        conv.id === activeConversationId
          ? {
              ...conv,
              messages: [...updatedMessages, aiMessage],
              updatedAt: new Date().toISOString()
            }
          : conv
      );
      saveConversations(finalConversations);
      
    } catch (error) {
      console.error('发送消息失败:', error);
      
      // 显示详细错误信息
      let errorMessage = '发送消息失败：';
      if (error.message.includes('401')) {
        errorMessage += 'API Key无效，请检查您的API Key是否正确。';
      } else if (error.message.includes('429')) {
        errorMessage += 'API调用频率超限，请稍后重试。';
      } else if (error.message.includes('insufficient_quota')) {
        errorMessage += 'API配额不足，请检查您的账户余额。';
      } else {
        errorMessage += error.message;
      }
      
      alert(errorMessage);
      
      // 添加错误消息到对话中
      const errorMessage_obj = {
        id: uuidv4(),
        role: 'assistant',
        content: `❌ 错误：${errorMessage}`,
        timestamp: new Date().toISOString()
      };
      
      const errorConversations = conversations.map(conv =>
        conv.id === activeConversationId
          ? {
              ...conv,
              messages: [...updatedMessages, errorMessage_obj],
              updatedAt: new Date().toISOString()
            }
          : conv
      );
      saveConversations(errorConversations);
    } finally {
      setIsLoading(false);
    }
  };

  // 处理回车键
  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const activeConversation = conversations.find(conv => conv.id === activeConversationId);

  return (
    <div className="h-full flex">
      {/* 对话列表侧边栏 */}
      <div className="w-80 border-r border-gray-200 flex flex-col">
        {/* 侧边栏头部 */}
        <div className="p-4 border-b border-gray-200">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-gray-900">AI 对话</h3>
            <div className="flex items-center space-x-2">
              <button
                onClick={() => setShowSettings(true)}
                className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
                title="设置"
              >
                <SettingsIcon size={16} />
              </button>
              <button
                onClick={createNewConversation}
                className="btn-primary flex items-center space-x-2 text-sm"
              >
                <PlusIcon size={16} />
                <span>新对话</span>
              </button>
            </div>
          </div>
        </div>
        
        {/* 对话列表 */}
        <div className="flex-1 overflow-y-auto">
          {conversations.length === 0 ? (
            <div className="p-4 text-center text-gray-500">
              <p>还没有对话</p>
              <p className="text-sm mt-1">点击"新对话"开始聊天</p>
            </div>
          ) : (
            <div className="space-y-1 p-2">
              {conversations.map((conversation) => (
                <div
                  key={conversation.id}
                  onClick={() => setActiveConversationId(conversation.id)}
                  className={`p-3 rounded-lg cursor-pointer transition-colors group ${
                    activeConversationId === conversation.id
                      ? 'bg-primary-50 border border-primary-200'
                      : 'hover:bg-gray-50'
                  }`}
                >
                  <div className="flex items-start justify-between">
                    <div className="flex-1 min-w-0">
                      <h4 className="font-medium text-gray-900 truncate">
                        {conversation.title}
                      </h4>
                      <p className="text-sm text-gray-500 mt-1">
                        {conversation.messages.length} 条消息
                      </p>
                      <p className="text-xs text-gray-400 mt-1">
                        {new Date(conversation.updatedAt).toLocaleDateString()}
                      </p>
                    </div>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        deleteConversation(conversation.id);
                      }}
                      className="opacity-0 group-hover:opacity-100 p-1 text-gray-400 hover:text-red-500 transition-all"
                    >
                      <TrashIcon size={14} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
      
      {/* 聊天区域 */}
      <div className="flex-1 flex flex-col">
        {activeConversation ? (
          <>
            {/* 聊天头部 */}
            <div className="p-4 border-b border-gray-200 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-semibold text-gray-900">{activeConversation.title}</h2>
                <p className="text-sm text-gray-500">
                  {activeConversation.messages.length} 条消息 | 模型: {model}
                </p>
              </div>
              <button
                onClick={clearCurrentConversation}
                className="btn-secondary text-sm"
              >
                清空对话
              </button>
            </div>
            
            {/* 消息列表 */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {activeConversation.messages.length === 0 ? (
                <div className="text-center py-12 text-gray-500">
                  <div className="text-4xl mb-4">🤖</div>
                  <p className="text-lg mb-2">开始新的对话</p>
                  <p className="text-sm">向AI助手提问任何问题</p>
                </div>
              ) : (
                activeConversation.messages.map((msg) => (
                  <div
                    key={msg.id}
                    className={`flex ${
                      msg.role === 'user' ? 'justify-end' : 'justify-start'
                    }`}
                  >
                    <div
                      className={`max-w-[70%] rounded-lg p-3 ${
                        msg.role === 'user'
                          ? 'bg-primary-600 text-white'
                          : 'bg-gray-100 text-gray-900'
                      }`}
                    >
                      <div className="whitespace-pre-wrap">{msg.content}</div>
                      <div
                        className={`text-xs mt-2 ${
                          msg.role === 'user' ? 'text-primary-100' : 'text-gray-500'
                        }`}
                      >
                        {new Date(msg.timestamp).toLocaleTimeString()}
                      </div>
                    </div>
                  </div>
                ))
              )}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-gray-100 rounded-lg p-3">
                    <div className="flex items-center space-x-2">
                      <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-primary-600"></div>
                      <span className="text-gray-600">AI正在思考...</span>
                    </div>
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>
            
            {/* 输入区域 */}
            <div className="p-4 border-t border-gray-200">
              <div className="flex space-x-2">
                <textarea
                  value={message}
                  onChange={(e) => setMessage(e.target.value)}
                  onKeyPress={handleKeyPress}
                  placeholder="输入您的问题..."
                  className="flex-1 resize-none border border-gray-300 rounded-lg p-3 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent"
                  rows={3}
                  disabled={isLoading}
                />
                <button
                  onClick={sendMessage}
                  disabled={!message.trim() || isLoading}
                  className="btn-primary flex items-center space-x-2 self-end disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <SendIcon size={16} />
                  <span>发送</span>
                </button>
              </div>
            </div>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center text-gray-500">
            <div className="text-center">
              <p className="text-lg mb-2">🤖</p>
              <p>选择一个对话开始聊天</p>
              <p className="text-sm mt-1">或创建新对话</p>
            </div>
          </div>
        )}
      </div>
      
      {/* 设置弹窗 */}
      {showSettings && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-96 max-h-[80vh] overflow-y-auto">
            <h3 className="text-lg font-semibold mb-4">AI 设置</h3>
            
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  API Key *
                </label>
                <input
                  type="password"
                  value={tempApiKey}
                  onChange={(e) => setTempApiKey(e.target.value)}
                  placeholder="请输入您的OpenAI API Key"
                  className="input-field"
                />
                <p className="text-xs text-gray-500 mt-1">
                  获取API Key: <a href="https://platform.openai.com/api-keys" target="_blank" rel="noopener noreferrer" className="text-primary-600 hover:underline">OpenAI官网</a>
                </p>
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  API端点
                </label>
                <input
                  type="text"
                  value={apiEndpoint}
                  onChange={(e) => setApiEndpoint(e.target.value)}
                  placeholder="https://api.openai.com/v1/chat/completions"
                  className="input-field"
                />
                <p className="text-xs text-gray-500 mt-1">
                  可以使用其他兼容OpenAI API的服务
                </p>
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  模型
                </label>
                <select
                  value={model}
                  onChange={(e) => setModel(e.target.value)}
                  className="input-field"
                >
                  <option value="gpt-3.5-turbo">GPT-3.5 Turbo</option>
                  <option value="gpt-4">GPT-4</option>
                  <option value="gpt-4-turbo-preview">GPT-4 Turbo</option>
                </select>
              </div>
              
              <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-3">
                <p className="text-xs text-yellow-800">
                  ⚠️ 安全提示：API Key将存储在浏览器本地。在生产环境中，建议通过后端代理API调用以保护密钥安全。
                </p>
              </div>
            </div>
            
            <div className="flex justify-end space-x-2 mt-6">
              <button
                onClick={() => {
                  setShowSettings(false);
                  setTempApiKey(apiKey);
                }}
                className="btn-secondary"
              >
                取消
              </button>
              <button
                onClick={saveApiKey}
                disabled={!tempApiKey.trim()}
                className="btn-primary flex items-center space-x-2 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <SaveIcon size={16} />
                <span>保存</span>
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AIChat;
